<?php
require dirname(__DIR__) . '/src/bootstrap.php';
$user=require_admin();
if($_SERVER['REQUEST_METHOD']!=='POST'){redirect('admin/inscripciones.php');}
verify_csrf();$id=(int)($_POST['id']??0);$action=$_POST['accion']??'';$obs=trim((string)($_POST['observaciones']??''));
try{$pdo->beginTransaction();$stmt=$pdo->prepare('SELECT i.id,i.evento_id,i.codigo,i.estado,e.cupos FROM inscripciones i JOIN eventos e ON e.id=i.evento_id WHERE i.id=? FOR UPDATE');$stmt->execute([$id]);$r=$stmt->fetch();if(!$r||$r['estado']!=='pago_pendiente'){throw new RuntimeException('La inscripción ya fue procesada.');}
if($action==='confirmar'){if($r['cupos']!==null){$c=$pdo->prepare("SELECT COUNT(*) FROM inscripciones WHERE evento_id=? AND estado IN ('pago_confirmado','kit_entregado')");$c->execute([$r['evento_id']]);if((int)$c->fetchColumn()>=(int)$r['cupos']){throw new RuntimeException('No quedan cupos disponibles.');}}$pdo->prepare("UPDATE pagos SET estado='confirmado',validado_por=?,fecha_validacion=NOW(),observaciones=NULL WHERE inscripcion_id=?")->execute([$user['id'],$id]);$pdo->prepare("UPDATE inscripciones SET estado='pago_confirmado' WHERE id=?")->execute([$id]);audit($pdo,$user['id'],'confirmar_pago','inscripcion',$id,['codigo'=>$r['codigo']]);$msg='Pago confirmado y cupo reservado.';
}elseif($action==='rechazar'){if($obs===''){throw new RuntimeException('Indique el motivo del rechazo.');}$pdo->prepare("UPDATE pagos SET estado='rechazado',validado_por=?,fecha_validacion=NOW(),observaciones=? WHERE inscripcion_id=?")->execute([$user['id'],$obs,$id]);$pdo->prepare("UPDATE inscripciones SET estado='pago_rechazado' WHERE id=?")->execute([$id]);audit($pdo,$user['id'],'rechazar_pago','inscripcion',$id,['motivo'=>$obs]);$msg='Comprobante rechazado.';}else{throw new RuntimeException('Acción no válida.');}$pdo->commit();flash('success',$msg);}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();flash('danger',$e->getMessage());}redirect('admin/ver.php?id='.$id);
